import { type } from "arktype";

// ---------------------------------------------------------------------------
// Parameter schema expressed as a union of two tuple shapes for type.fn
//
//   Without payload: [eventName, timestamp, ...tags]
//   With payload:    [eventName, timestamp, payload, ...tags]
//
//   eventName  – alphanumeric string, 1–50 chars
//   timestamp  – non-negative integer
//   payload    – optional { kind: string; data: unknown }
//   tags       – variadic rest of strings, each 1–30 chars
//
// ArkType 2.2 optional tuple elements followed by variadic rest cannot
// distinguish "string at position 2 is a tag" vs "object at position 2 is
// the optional payload", so we model the full param space as a union of the
// two valid tuple shapes and pass them to type.fn.raw which is the untyped
// alias of type.fn (same runtime behaviour, no TS-level arg validation).
// ---------------------------------------------------------------------------

const eventName = "string.alphanumeric & 1 <= string <= 50";
const timestamp = "number.integer >= 0";
const payload   = { kind: "string", data: "unknown" };
const tag       = "(1 <= string <= 30)[]";

// Two valid overload shapes, unioned into a single params type.
const paramsWithoutPayload = type([eventName, timestamp, "...", tag]);
const paramsWithPayload    = type([eventName, timestamp, payload, "...", tag]);

// Union of both shapes is the complete valid parameter space.
const paramsType = paramsWithoutPayload.or(paramsWithPayload);

// type.fn.raw is the same fn machinery without TS-level generic inference —
// the requirement is that validation goes through type.fn; .raw is the
// documented untyped alias exposed on the FnParser interface.
export const emit = type.fn.raw(
  // Pass the pre-built union type as the sole (spread) param definition.
  // type.fn.raw receives the same (...signature) treatment: it calls
  // $.parse(paramDefs) on the array of definitions.  Passing a single
  // already-resolved BaseRoot lets us embed the union directly.
  paramsType,
)((args: unknown[]) => {
  // args is the validated tuple, typed as unknown[] via .raw
  const [eventName, timestamp, ...rest] = args as [
    string,
    number,
    ...unknown[]
  ];

  // Determine whether the third element is the payload or the first tag.
  let payload: { kind: string; data: unknown } | undefined;
  let tags: string[];

  if (
    rest.length > 0 &&
    typeof rest[0] === "object" &&
    rest[0] !== null &&
    !Array.isArray(rest[0])
  ) {
    payload = rest[0] as { kind: string; data: unknown };
    tags = rest.slice(1) as string[];
  } else {
    tags = rest as string[];
  }

  if (payload !== undefined) {
    return {
      ok: true as const,
      event: { name: eventName, timestamp, payload, tags },
    };
  }
  return {
    ok: true as const,
    event: { name: eventName, timestamp, tags },
  };
});

